    hexi::deserializer<std::span<const uint8_t>> deserializer(buffer);

    NetworkPacket packet;

    // Read packet_id using operator>>
    deserializer >> packet.packet_id;

    // Read username using prefixed adaptor
    deserializer >> hexi::prefixed(packet.username);

    // Read score count and use read_container to read scores vector
    uint32_t score_count;
    deserializer >> score_count;
    deserializer.read_container(packet.scores, score_count);

    // Read metadata string as null-terminated
    deserializer >> hexi::null_terminated(packet.metadata);

    // Skip any remaining padding bytes
    deserializer.skip(buffer.size() - deserializer.total_read());

