    auto peeked = peek_data_without_advancing(buffer_data, 3);

    EXPECT_EQ(3, peeked.size());
    EXPECT_EQ(10, peeked[0]);
    EXPECT_EQ(20, peeked[1]);
    EXPECT_EQ(30, peeked[2]);
}

TEST(BufferAdaptors, PeekThenRead) {
    std::vector<uint8_t> buffer_data = {100, 200, 44, 144};
    std::vector<uint8_t> buffer = buffer_data;

    hexi::pmc::buffer_read_adaptor read_adaptor(buffer);

    // Peek first 2 bytes
    std::vector<uint8_t> peeked(2);
    read_adaptor.copy(peeked.data(), 2);

    // Verify peeked data
    EXPECT_EQ(100, peeked[0]);
    EXPECT_EQ(200, peeked[1]);

    // Verify read pointer hasn't advanced (size should still be full)
    EXPECT_EQ(buffer_data.size(), read_adaptor.size());

    // Now read to consume
    std::vector<uint8_t> read_data(2);
    read_adaptor.read(read_data.data(), 2);

    // Verify read data matches peeked data
    EXPECT_EQ(peeked, read_data);

    // Verify size decreased
    EXPECT_EQ(buffer_data.size() - 2, read_adaptor.size());
}

TEST(BufferAdaptors, ReadPtrAccess) {
    std::vector<uint8_t> buffer_data = {5, 10, 15, 20};
    std::vector<uint8_t> buffer = buffer_data;

    hexi::pmc::buffer_read_adaptor read_adaptor(buffer);

    // Get read pointer
    auto* read_pos = read_adaptor.read_ptr();

    // Verify pointer points to correct data
    EXPECT_EQ(5, static_cast<uint8_t>(*read_pos));

    // Read one byte
    uint8_t value;
    read_adaptor.read(&value);

    EXPECT_EQ(5, value);

    // Get new read pointer
    auto* new_read_pos = read_adaptor.read_ptr();
    EXPECT_EQ(10, static_cast<uint8_t>(*new_read_pos));
